document.addEventListener("DOMContentLoaded",async()=>{const tableBody=document.querySelector("#agency-inquiries .data-table tbody");if(!tableBody){console.error("Could not find the table body for agency inquiries.");return}try{const response=await fetch("/api/get-agency-inquiries");if(!response.ok){throw new Error(`Failed to fetch agency inquiries: ${response.statusText}`)}const inquiries=await response.json();if(inquiries.length===0){tableBody.innerHTML='<tr><td colspan="8">No agency inquiries found.</td></tr>';return}tableBody.innerHTML="";inquiries.sort((a,b)=>new Date(b.timestamp)-new Date(a.timestamp));inquiries.forEach(inquiry=>{const row=document.createElement("tr");row.innerHTML=`
                <td>${inquiry.agencyName||"N/A"}</td>
                <td><a href="${inquiry.website}" target="_blank">${inquiry.website}</a></td>
                <td>${inquiry.contactPerson||"N/A"}</td>
                <td><a href="mailto:${inquiry.contactEmail}">${inquiry.contactEmail}</a></td>
                <td>${inquiry.phoneNumber||"N/A"}</td>
                <td>${inquiry.clientVolume||"N/A"}</td>
                <td>${inquiry.message||"N/A"}</td>
                <td>${new Date(inquiry.timestamp).toLocaleString()}</td>
            `;tableBody.appendChild(row)})}catch(error){console.error("Error fetching and displaying agency inquiries:",error);if(tableBody){tableBody.innerHTML='<tr><td colspan="8">Failed to load agency inquiries. Please try again later.</td></tr>'}}});